6757 /// If we have an icmp le or icmp ge instruction with a constant operand, turn
6758 /// it into the appropriate icmp lt or icmp gt instruction. This transform
6759 /// allows them to be folded in visitICmpInst.
6760 static ICmpInst *canonicalizeCmpWithConstant(ICmpInst &I) {
6761   ICmpInst::Predicate Pred = I.getPredicate();
6762   if (ICmpInst::isEquality(Pred) || !ICmpInst::isIntPredicate(Pred) ||
6763       InstCombiner::isCanonicalPredicate(Pred))
6764     return nullptr;
6765 
6766   Value *Op0 = I.getOperand(0);
6767   Value *Op1 = I.getOperand(1);
6768   auto *Op1C = dyn_cast<Constant>(Op1);
6769   if (!Op1C)
6770     return nullptr;
6771 
6772   auto FlippedStrictness =
6773       InstCombiner::getFlippedStrictnessPredicateAndConstant(Pred, Op1C);
6774   if (!FlippedStrictness)
6775     return nullptr;
6776 
6777   return new ICmpInst(FlippedStrictness->first, Op0, FlippedStrictness->second);
6778 }
