2358     }
2359     if (Pred == ICmpInst::ICMP_ULT) {
2360       // ULE is the same as above, but ULE is canonicalized to ULT, so convert:
2361       // (X << S) <=u C is equiv to X <=u (C >> S) for all C
2362       // (X << S) <u (C + 1) is equiv to X <u (C >> S) + 1 if C <u ~0u
